import{_ as e,o as r,c as i,ah as h}from"./chunks/framework.D-EW4Mou.js";const b=JSON.parse('{"title":"高可用与容错","description":"","frontmatter":{"title":"高可用与容错","order":45},"headers":[],"relativePath":"server/distribute/qos/ha/index.md","filePath":"server/distribute/qos/ha/index.md"}'),l={name:"server/distribute/qos/ha/index.md"};function n(t,a,d,s,o,c){return r(),i("div",null,[...a[0]||(a[0]=[h('<h1 id="高可用与容错" tabindex="-1">高可用与容错 <a class="header-anchor" href="#高可用与容错" aria-label="Permalink to “高可用与容错”">​</a></h1><p>高可用（High Availability, HA）是指系统在长时间内提供服务的能力，通常用可用性（如 99.9%）表示。容错（Fault Tolerance）是指系统在部分组件故障时继续提供服务的能力。</p><h2 id="可用性指标" tabindex="-1">可用性指标 <a class="header-anchor" href="#可用性指标" aria-label="Permalink to “可用性指标”">​</a></h2><h3 id="可用性等级" tabindex="-1">可用性等级 <a class="header-anchor" href="#可用性等级" aria-label="Permalink to “可用性等级”">​</a></h3><p>99.9%（8.76 小时/年）、99.99%（52.56 分钟/年）、99.999%（5.26 分钟/年）。</p><h3 id="mtbf-和-mttr" tabindex="-1">MTBF 和 MTTR <a class="header-anchor" href="#mtbf-和-mttr" aria-label="Permalink to “MTBF 和 MTTR”">​</a></h3><p>MTBF（平均故障间隔时间）、MTTR（平均修复时间）。</p><p>可用性 = MTBF / (MTBF + MTTR)。</p><h2 id="冗余设计" tabindex="-1">冗余设计 <a class="header-anchor" href="#冗余设计" aria-label="Permalink to “冗余设计”">​</a></h2><h3 id="服务冗余" tabindex="-1">服务冗余 <a class="header-anchor" href="#服务冗余" aria-label="Permalink to “服务冗余”">​</a></h3><p>部署多个服务实例，负载均衡器将请求分发到健康的服务实例。</p><h3 id="数据冗余" tabindex="-1">数据冗余 <a class="header-anchor" href="#数据冗余" aria-label="Permalink to “数据冗余”">​</a></h3><p>主从复制、多主复制、数据一致性（强一致性、最终一致性）。</p><h3 id="硬件冗余" tabindex="-1">硬件冗余 <a class="header-anchor" href="#硬件冗余" aria-label="Permalink to “硬件冗余”">​</a></h3><p>磁盘 RAID、双电源、双网卡、双交换机。</p><h2 id="故障检测" tabindex="-1">故障检测 <a class="header-anchor" href="#故障检测" aria-label="Permalink to “故障检测”">​</a></h2><h3 id="健康检查" tabindex="-1">健康检查 <a class="header-anchor" href="#健康检查" aria-label="Permalink to “健康检查”">​</a></h3><p>Liveness（存活检查）、Readiness（就绪检查）。</p><p>健康检查方式：HTTP 端点、TCP 端口、命令。</p><h3 id="故障判定" tabindex="-1">故障判定 <a class="header-anchor" href="#故障判定" aria-label="Permalink to “故障判定”">​</a></h3><p>连续 N 次健康检查失败后，判定服务故障。</p><h2 id="故障恢复" tabindex="-1">故障恢复 <a class="header-anchor" href="#故障恢复" aria-label="Permalink to “故障恢复”">​</a></h2><h3 id="自动重启" tabindex="-1">自动重启 <a class="header-anchor" href="#自动重启" aria-label="Permalink to “自动重启”">​</a></h3><p>服务崩溃时自动重启，退避策略避免重启循环。</p><h3 id="故障转移" tabindex="-1">故障转移 <a class="header-anchor" href="#故障转移" aria-label="Permalink to “故障转移”">​</a></h3><p>主节点故障时，从节点提升为主节点。</p><h3 id="限流降级" tabindex="-1">限流降级 <a class="header-anchor" href="#限流降级" aria-label="Permalink to “限流降级”">​</a></h3><p>服务过载时限流保护，依赖服务故障时降级。</p><h2 id="熔断器" tabindex="-1">熔断器 <a class="header-anchor" href="#熔断器" aria-label="Permalink to “熔断器”">​</a></h2><h3 id="熔断器模式" tabindex="-1">熔断器模式 <a class="header-anchor" href="#熔断器模式" aria-label="Permalink to “熔断器模式”">​</a></h3><p>关闭（Closed）、开启（Open）、半开（Half-Open）三种状态。</p><p>连续 N 次失败后，熔断器开启，直接返回失败。</p><h2 id="超时与重试" tabindex="-1">超时与重试 <a class="header-anchor" href="#超时与重试" aria-label="Permalink to “超时与重试”">​</a></h2><h3 id="超时" tabindex="-1">超时 <a class="header-anchor" href="#超时" aria-label="Permalink to “超时”">​</a></h3><p>超时是等待响应的最长时间，应该根据 P99 延迟设置。</p><h3 id="重试" tabindex="-1">重试 <a class="header-anchor" href="#重试" aria-label="Permalink to “重试”">​</a></h3><p>重试策略：立即重试、固定延迟重试、指数退避重试。</p><p>只重试幂等操作。</p>',38)])])}const m=e(l,[["render",n]]);export{b as __pageData,m as default};
